#include<bits/stdc++.h>
using namespace std;
const int N = 1e6+5;
long long n,num,a[N],s[N],k,ans;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];num+=a[i];
    }
    num/=n;
    for(int i=1;i<=n;i++){
        a[i]-=num;s[i]=s[i-1]+a[i];
    }
    sort(s+1,s+n+1);
    k=(n+1)/2;
    for(int i=1;i<=n;i++)
        ans+=abs(s[i]-s[k]);
    cout<<ans;
    return 0;
}
